const now = new Date();

const mexicoTime = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Mexico_City',
  weekday: 'short',
  hour: 'numeric',
  hour12: false
}).formatToParts(now);

const day = mexicoTime.find(x => x.type === 'weekday').value;
const hour = parseInt(
  mexicoTime.find(x => x.type === 'hour').value
);

const businessHours =
  ['Mon','Tue','Wed','Thu','Fri'].includes(day) &&
  hour >= 8 &&
  hour < 17;

for (const item of $input.all()) {
  item.json.businessHours = businessHours;
}

return $input.all();

const data = $input.first().json;

return {
  json: {
    messageType: data.voice_message ? 'audio' : 'text',
    text_message: data.text_message,
    voice_message: data.voice_message,
    conversation: data.conversation,
    sender: data.sender,
    sessionId: data.sessionId,
    data_time: data.data_time
  }
};

const phone = $json.body.conversation.contact_inbox.source_id;

